import React from "react";
import moment from "moment";

import Layout from "../layouts/default";
import PageHeader from "../components/PageHeader";
import PageContent from "../components/Content";
import Loader from "../components/Loader";
import Card from "../components/Card";
import Link from "../components/Link";
import fetchPatrons from "../utils/fetchPatrons";
import fetchPayPalDonors from "../utils/fetchPayPalDonors";

let cachedPatrons, cachedPayPalDonors;

export default class Donors extends React.Component {
    constructor(props) {
        super(props);

        this.state = {
            patrons: [],
            paypalDonors: [],
        };
    }

    componentDidMount() {
        if (cachedPatrons) {
            this.setState({ patrons: cachedPatrons });
        } else {
            fetchPatrons().then(fetchedPatrons => {
                cachedPatrons = fetchedPatrons;

                this.setState({ patrons: fetchedPatrons });
            }).catch(console.error);
        }

        if (cachedPayPalDonors) {
            this.setState({ paypalDonors: cachedPayPalDonors });
        }
        else {
            fetchPayPalDonors().then(fetchedPayPalDonors => {
                cachedPayPalDonors = fetchedPayPalDonors;

                this.setState({ paypalDonors: fetchedPayPalDonors });
            }).catch(console.error);
        }
    }

    render () {
        return (
            <Layout
                title="Donors"
                description="These are all the people who have donated and shared their appreciation for the continous development of The Bastion Bot Project and kept it alive."
                image=""
            >
                <PageHeader />

                <PageContent>
                    <div css={{
                        textAlign: "center",
                        marginBottom: 50,
                    }}>
                        <h1>Donors</h1>
                        <p>
                            These are all the people who have donated and shared their
                            appreciation for the continous development of The Bastion Bot
                            Project and kept it alive.
                        </p>
                        <p>
                            If you also want to share your appreciation and get cool rewards,
                            all while supporting the development of Bastion, you can <Link
                            to="/donate">donate</Link> too.
                        </p>
                    </div>

                    <div css={{
                        display: "flex",
                        flexWrap: "wrap",
                        justifyContent: "center",
                    }}>
                        {
                            this.state.patrons.length
                            ?   this.state.patrons
                                .filter(user => (
                                    user.patron_status === "active_patron" || user.lifetime_support_cents !== 0
                                ))
                                .sort((a, b) => b.lifetime_support_cents - a.lifetime_support_cents)
                                .map((user, i) => (
                                    <Card
                                        key={ i }
                                        title={ user.discord_tag || user.full_name }
                                        description={
                                            user.patron_status === "active_patron"
                                            ? `Patron since ${moment(user.pledge_relationship_start).toNow(true)}`
                                            : `Patron until ${moment(user.last_charge_date).toNow(true)} ago`
                                        }
                                        center={ true }
                                        middle={ true }
                                        dark={ true }
                                        // image={ user.discord_avatar || user.image_url }
                                    />
                                ))
                            :   <></>
                        }
                        {
                            this.state.paypalDonors.length
                            ?   this.state.paypalDonors
                                .sort((a, b) => b.lifetime_support_cents - a.lifetime_support_cents)
                                .map((user, i) => (
                                    <Card
                                        key={ i }
                                        title={ user.discord_tag }
                                        description={ `Last donated ${moment(user.last_donation_date).toNow(true)} ago` }
                                        center={ true }
                                        middle={ true }
                                        dark={ true }
                                        // image={ user.discord_avatar }
                                    />
                                ))
                            :   <></>
                        }
                        {
                            this.state.patrons.length && this.state.paypalDonors.length
                            ? <></>
                            : <Loader />
                        }
                    </div>
                </PageContent>
            </Layout>
        );
    }
};
