export default () => {
    return new Promise((resolve, reject) => {
        window.fetch("https://thebastionbot.herokuapp.com/paypal/donors", {
            headers: {
                "UserAgent": "The Bastion Bot Website (https://bastionbot.org)",
            },
        })
        .then(res => res.json())
        .then(data => {
            resolve(data);
        })
        .catch(e => reject(e));
    });
};
